    "brand": "ASICS",
    "category": "sapatilhas",
    "price": 90.99,
    "oldPrice": 129.99,
    "rating": null,
    "image": "https://images2.productserve.com/?w=200&h=200&bg=white&trim=5&t=letterbox&url=ssl%3Awww.forumsport.com%2Fmedias%2Fmedias-1000993152-00-P-X-20241003171945.jpg%3Fcontext%3DbWFzdGVyfGltYWdlc3w5ODA3N3xpbWFnZS9qcGVnfGFHTXlMMmhpTmk4eE1qUXdPRGM0TlRjMk5ETTRNaTl0WldScFlYTmZNVEF3TURrNU16RTFNbDh3TUY5UVgxZ3RNakF5TkRFd01ETXhOekU1TkRVdWFuQm58Nzc3YjI3NjlkMTVlMmIwMzM2Y2ZjZGQyY2RmNjFmMTkyYTY2OGFlM2Q2ZmJkNTBlNTE5OGU3MDUyYmYzMWFjNw&feedId=58083&k=fea2fab6febed268baec2140a9c381ba5bef6c8f",
    "source": "forum-sport-es",
    "sourceProductId": "4686208",
